 31	void x2ap_timers_init(x2ap_timers_t *t,
 32	    int t_reloc_prep,
 33	    int tx2_reloc_overall,
 34	    int t_dc_prep,
 35	    int t_dc_overall)
 36	{
 37	  t->tti               = 0;
 38	  t->t_reloc_prep      = t_reloc_prep;
 39	  t->tx2_reloc_overall = tx2_reloc_overall;
 40	  t->t_dc_prep         = t_dc_prep;
 41	  t->t_dc_overall      = t_dc_overall;
 42	}
