 44	void x2ap_check_timers(instance_t instance)
 45	{
 46	  x2ap_eNB_instance_t          *instance_p;
 47	  x2ap_timers_t                *t;
 48	  x2ap_id_manager              *m;
 49	  int                          i;
 50	  x2ap_handover_cancel_cause_t cause;
 51	  void                         *target;
 52	  MessageDef                   *msg;
 53	  int                          x2_ongoing;
 54	
 55	  instance_p = x2ap_eNB_get_instance(instance);
 56	  DevAssert(instance_p != NULL);
 57	
 58	  t = &instance_p->timers;
 59	  m = &instance_p->id_manager;
 60	
 61	  /* increment subframe count */
 62	  t->tti++;
 63	
 64	  x2_ongoing = 0;
 65	
 66	  for (i = 0; i < X2AP_MAX_IDS; i++) {
 67	    if (m->ids[i].rnti == -1) continue;
 68	
 69	    if (m->ids[i].state == X2ID_STATE_SOURCE_PREPARE ||
 70	        m->ids[i].state == X2ID_STATE_SOURCE_OVERALL)
 71	      x2_ongoing++;
 72	
 73	    if (m->ids[i].state == X2ID_STATE_SOURCE_PREPARE &&
 74	        t->tti > m->ids[i].t_reloc_prep_start + t->t_reloc_prep) {
 75	      LOG_I(X2AP, "X2 timeout reloc prep\n");
 76	      /* t_reloc_prep timed out */
 77	      cause = X2AP_T_RELOC_PREP_TIMEOUT;
 78	      goto lte_handover_timeout;
 79	    }
 80	
 81	    if (m->ids[i].state == X2ID_STATE_SOURCE_OVERALL &&
 82	        t->tti > m->ids[i].tx2_reloc_overall_start + t->tx2_reloc_overall) {
 83	      LOG_I(X2AP, "X2 timeout reloc overall\n");
 84	      /* tx2_reloc_overall timed out */
 85	      cause = X2AP_TX2_RELOC_OVERALL_TIMEOUT;
 86	      goto lte_handover_timeout;
 87	    }
 88	
 89	    if (m->ids[i].state == X2ID_STATE_NSA_ENB_PREPARE &&
 90	        t->tti > m->ids[i].t_dc_prep_start + t->t_dc_prep) {
 91	      int id_source;
 92	      int id_target;
 93	
 94	      LOG_I(X2AP, "X2 timeout DC prep\n");
 95	      /* t_dc_prep timed out */
 96	      target = x2ap_id_get_target(m, i);
 97	      id_source = x2ap_id_get_id_source(m, i);
 98	      id_target = x2ap_id_get_id_target(m, i);
 99	      x2ap_eNB_generate_ENDC_x2_SgNB_release_request(instance_p, target,
100	                                                     id_source, id_target,
101	                                                     X2AP_CAUSE_T_DC_PREP_TIMEOUT);
102	
103	      /* inform RRC of timeout */
104	      msg = itti_alloc_new_message(TASK_X2AP, 0, X2AP_ENDC_DC_PREP_TIMEOUT);
105	      X2AP_ENDC_DC_PREP_TIMEOUT(msg).rnti  = x2ap_id_get_rnti(m, i);
106	      itti_send_msg_to_task(TASK_RRC_ENB, instance_p->instance, msg);
107	
108	      /* remove UE from X2AP */
109	      x2ap_release_id(m, i);
110	
111	      continue;
112	    }
113	
114	    if (m->ids[i].state == X2ID_STATE_NSA_GNB_OVERALL &&
115	        t->tti > m->ids[i].t_dc_overall_start + t->t_dc_overall) {
116	      int id_source;
117	      int id_target;
118	
119	      LOG_I(X2AP, "X2 timeout DC overall\n");
120	      /* t_dc_overall timed out */
121	      target = x2ap_id_get_target(m, i);
122	      id_source = x2ap_id_get_id_source(m, i);
123	      id_target = x2ap_id_get_id_target(m, i);
124	      x2ap_eNB_generate_ENDC_x2_SgNB_release_required(instance_p, target,
125	              id_source, id_target, X2AP_CAUSE_T_DC_OVERALL_TIMEOUT);
126	
127	      /* inform RRC of timeout */
128	      msg = itti_alloc_new_message(TASK_X2AP, 0, X2AP_ENDC_DC_OVERALL_TIMEOUT);
129	      X2AP_ENDC_DC_OVERALL_TIMEOUT(msg).rnti  = x2ap_id_get_rnti(m, i);
130	      itti_send_msg_to_task(TASK_RRC_GNB, instance_p->instance, msg);
131	
132	      /* remove UE from X2AP */
133	      x2ap_release_id(m, i);
134	
135	      continue;
136	    }
137	
138	    /* no timeout -> check next UE */
139	    continue;
140	
141	lte_handover_timeout:
142	    /* inform target about timeout */
143	    target = x2ap_id_get_target(m, i);
144	    x2ap_eNB_generate_x2_handover_cancel(instance_p, target, i, cause);
145	
146	    /* inform RRC of cancellation */
147	    msg = itti_alloc_new_message(TASK_X2AP, 0, X2AP_HANDOVER_CANCEL);
148	    X2AP_HANDOVER_CANCEL(msg).rnti  = x2ap_id_get_rnti(m, i);
149	    X2AP_HANDOVER_CANCEL(msg).cause = cause;
150	    itti_send_msg_to_task(TASK_RRC_ENB, instance_p->instance, msg);
151	
152	    /* remove UE from X2AP */
153	    x2ap_release_id(m, i);
154	  }
155	
156	  if (x2_ongoing && t->tti % 1000 == 0)
157	    LOG_I(X2AP, "X2 has %d process ongoing\n", x2_ongoing);
158	}
