      if(new_instance->cell_type == CELL_MACRO_GNB){
        new_instance->nr_band[i]              = x2ap_register_eNB->nr_band[i];
        new_instance->tdd_nRARFCN[i]             = x2ap_register_eNB->nrARFCN[i];
      }
      else{
